INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1172505','Славимо Іллю','Музика: А. Гнатишин Слова: о. В. Б. Мендрунь','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Всі миряни, восхвалімо славного Іллю,
Хлопчик воскресає удови з Сарепти,
Голоду немає - впали сльози лепти.

Приспів:
Хто його не знає? Серце звеселяє
Глас Господній - муж Ілля!
Маєш втіхи повну міру,
Перед Богом нас згадай,
Утверди спасенну віру,
Щоб не гинув отчий край!

Знищив лжепророків
Гнівом справедливим...
Йдуть живі потоки
На засохлі ниви.

Приспів.

В небо він вознісся
У вогненнім леті...
Божий люд розрісся
По усій планеті.

Приспів.
О, пророче дивний,
Був ти на Таворі
І з Мойсеєм смирним
Бесідник Христові!

Приспів.

Маєш втіхи повну міру,
Перед Богом нас згадай,
Утверди спасенну віру,
Щоб не гинув отчий край.

Приспів.','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1172505'), datetime('now')),datetime('now'));
