INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_117101','Тадж-Махал','Музика: Гурт "Океан Ельзи" Слова: Святослав Вакарчук','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Мене питають, коли поїду,
