INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1175808','А там, на гори, там вітер рве','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.226','Виконує: В.Євтусяк, с.Лосє','1. А там на гори, там вітер рве,
А на долині там тишина.
Дівчини серце, мов жар, палає,
Тихе, спокійне, мов пташина.
Дівчини серце, мов жар, палає,
Тихе, спокійне, мов пташина.

2. Чого с, дівчатко, таке смутне?
Світ так веселий, як та весна.
Молоді літа скоро минуться,
А ти зостанеш, як сирота.
Молоді літа скоро минуться,
А ти зостанеш, як сирота.

3. І час кохання скоро мине,
Лем позостане спомин про все.
Любилам хлопця і не забуду,
Котрий мя лишив, юж не верне.
Любилам хлопця і не забуду,
Котрий мя лишив, юж не верне.

4. Ой повернися, соколе мій,
Най подивлюся на образ твій.
Най поцілую личенько твоє,
Най тя пригорну, голубе мій.
Най поцілую личенько твоє,
Най тя пригорну, голубе мій','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1175808'), datetime('now')),datetime('now'));
