INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1176404','Прошу пані!','Музика: Віктор Морозов Слова: Андрій Панчишин. Виконує: Віктор Морозов','uk','ukraine_1991',NULL,NULL,'http://www.mo-productions.com/','Підібрав акорди (vperfetsjkyj@gmail.com), адже такі саме такі пісні повинні виконуватись під гітару вечорами у студентських гуртожитках чи біля вогнищ!','Прошу пані!
Dm
Я не маю права
Не сказати про таку красу
В пані гарні ноги - особливо права
Я великий букет пані принесу
Ага! Елєганцка нога
Ага! Ше й либонь дорога
Am
Шо то за кобіта!
Dm
Шо за фелічіта!
Мушу я почути як ми скаже "Ага!"
Прошу пана!
Ви так не шуткуйте
Ше ніхто так не балакав зі мнов
За своїм язичком трохи припильнуйте
Або дам по яях лівою ногов
Ага!
Елєганцка нога
Ага!
І одна і друга
А такі паньчохи роблят тилько влохи
Заладуй си букєт там де росне нога!
Прошу пані!
Шо то за говірка?
Я не чувім тих штубацких слів
Ту не Старий Самбір
Не Нова Бібірка
Ту так не говорат - ту є місто Львів!
Прошу пана!
Злазьте з фортеп''яна
Ти не батяр а телячий фляк
Стули собі писок
Пане грубіяне
Поцілуй ми в дупу!
Най ті трафит шляк!
Прошу пані!
Таку сльічну дупцю
Я до смерти годен цілувать
Прошу пані!
Хойці любцю-любцю
До самого рана не будемо спать
Ага!
Зла як Баба Яга
Ага!
Але гарна нога
Шо то за кобіта!
Голос як трембіта
Мушу я почути як ми скаже "Ага!"
Прошу пана!
Я пор''єдна дівка
Крем з айвону на фризурі тафт
Най ми пан покаже де його готівка
А по тому може вип''єм брудершафт
Ага!
Він до мене мруґа
Ага!
Але я дорога
Не піду задаром
Ні з одним батяром
Наперед заплати - потім буде "Ага!"
Прошу пані!
На Високім Замку
Я маршалек - я сі ту вродив
Виджу пані змерзла - прошу маринарку
Той зриває квітку хто ї не садив
Ага!...','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1176404'), datetime('now')),datetime('now'));
