INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1177622','Не ламай калини!','Українська народна пісня. Виконує: Фольклорний дует "Дуліби"','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Коли ти берегом ідеш,
То не ламай калини!
Коли ти в армію ідеш,
То не кохай дівчини!

Приспів:
Ой, помню, помню я той час - |
Ти плакала за мною           |
І на прощання раз у раз      |
Махала хустиною.             | (2)

Як їхав хлопець до войська,
Дівчина присягала,
Казала буде вірно ждать,
Хустину дарувала.

Приспів.

Пройшов годок, пройшов другий,
Козак з войська вертає,
Сади цвітуть, душа тремтить,
Аж серце завмирає.

Вишневий сад, зелений гай,   |
Калина коло хати,            |
Стріча солдата-вояка         |
Старенька його мати.         | (2)

Коли калина й одцвіте,
Тоді ламай калину!
Коли ти з армії прийдеш,
Тоді кохай дівчину!

Приспів.','[''pisni.org.ua'', ''cat:lirychni'', ''cat:narodni'', ''Пісні про кохання, ліричні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1177622'), datetime('now')),datetime('now'));
