INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1175828','Бивай мі здорова, ти дівчино моя','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.230','Виконує: Ольга Дудка, с.Лосє','1. Бивай мі здорова ти, дівчино моя,
Не забивай о мі, коли ласка твоя,
Я в дорогу виїжджаю, на серденьку тугу маю,
З тобов розстаюся, на Бога здаюся.

2. Їдь, милий, в дорогу, дорога щаслива.
Я на каждім кроці буду ти жичлива.
Лем скоро звертай з дороги, знаєш ти добрі,
Же вороги нам на перешкоді, любитися годі.

3. Милий у дорозі коня напуває,
Несут йому вістку - дівча заручают.
"Нехай си заручат, і так єї не звінчают,
Она мойом буде, не розлучат люде".

4. Запровадив милий коника до двора,
Вийд же, дівчинонько, най побесідую.
Стою, стою - не виходит, певно, она мном юж гордит.
Моя возлюблена певно заручена.

5. "Чогос ти, дівчино, товди не казала,
Як ти все од мене подарунки брала?"
"Забирай си свої дари, шукай собі іншой пари,
Я в них не ходила, тебе не любила".

6. "Билас ти, дівчино, як на небі зірка,
А тепер зав''янеш, як ружова квітка.
Не раз, не два ти зав''янеш, як на мене оком глянеш,
Спомнеш мої слова, не будеш щаслива"','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1175828'), datetime('now')),datetime('now'));
