INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1177303','Дивная година по всім світу стала','Українська народна пісня. Виконує: Древо','uk','ukraine_before_1917',NULL,NULL,'запис з Вконтактє ру',NULL,'Дивная година
По всім світу стала,
Та не одна сирітка  |
Без матінки стала.  | (2)

Ой, пішла сирітка
По світу блукати,
Своєї матусі        |
Рідної шукати.      | (2)

Господь зустрічає,
Став її питати:
Куди йдеш, сирітко?
Матінки шукати.
А куди йдеш, сирітко?
Матінки шукати.

Ой вернись, сирітко,
Бо далеко зайдеш,
Своєї матусі        |
Довіку не знайдеш!  | (2)

Ой, ой, хто ж то плаче
На моєму гробі?
А це ж я, матусю,   |
Прийми мене к собі! | (2)

Ой, рада б я, доню,
До себе прийняти.
Так землі багато -  |
Не можу я встати.   | (2)

Іди ж, моя доню,
Шукай собі долю,
Бо вже мені, доню,  |
Не жити з тобою!    | (2)

Ой, як тяжко-важко
Доленьки шукати
Ніхто не пригорне,  |
Як рідная мати!..   | (2)','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1177303'), datetime('now')),datetime('now'));
