INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_118606','Вже Весна воскресла','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Що за Господар, рясу якого можна орати-сіяти? Хто дає Світу Краси? Яку пшеницю сіяно, що за цибулю саджено? Пшеницев сІяна чи сіЯна? Гаїлки-Великдень: Українське свято Відродження Світа. Вже Весна воскресла: Принесла вам Красу Господарську Рясу. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Розспів: Вже Вес-на вос-крес-ла Що Ти нам при-нес-ла |(2) Вже Весна воскресла. А я вам принесла Дівоцькую Зброю. Принесла Вам Росу Парубоцьку Красу. А Дівоча Краса як на Калині Роса. А вже Весна скресла (1) А вже Весна скресла (2) Вже Весна воскресла Вже Весна воскресла (2) Вже Весна воскресла (3) Уже Весна й оскресла й оскресла А вже Весна Красна Благослови Мати Весну закликати Весна Наша Весна що Ти нам принесла (1) Весна Наша Весна що Ти нам принесла (2) Весно Наша Весно що Ти нам принесла (3) Весно Наша Весно що Ти нам принесла (4) Ой Весна Весна Днем Красна Весняночка Паняночка де ж Ти зимувала Весняночка Паняночка де Ти зимувала (1) Весняночка Паняночка де Ти зимувала (2) Ой Весна Весна да Весняночка Ой Весна Весна тай Весняночка Ой Весно Весно тай Весняночка Весняночка Паняночка хто по Тобі ходить Прийшла Весна з Квітками Благослови Мати Весну закликати. Весна іде Красу несе. Володар Володар й одчиняй Ворота. Ой но на Морі Павутиноньки. А в Горобейка Жінка Маленька. Сіяти Павучки-павучки. До Саду Дівчата до Саду Ой Білая Паутина по Тину повилась Ой Снодо Снодо Тонкая Там Біленьке Павутиння А ми в Кривого Танцю йдем. Ой Вінку Наш Вінку Хрещатий Барвінку Ой Данчику Білоданчику поплинь. Вибирай си кого любиш. Завтра вранці помандрую. Ідеологійне сполучення Різдва з Великоднем. Українське Різдвяне господарське свято не є ані весняне, ані літнє, бо припадає серед Зими і воно є передовсім реліґійним Святом, хоч має визначно господарську закраску; воно є традицією про перші первосвітні плоди землі і славить Бога, що їх зародив. (В сотвореному Господом Богом Раю немає пір року, там вічнозелений Сад: " Рай розвився, Господь звеселився! " Там інший — мітичний Святий, Сьвітий, час.) Лучиться воно ідеологійно, з особливіших мотивів, з Весняним Українським святом Великодня: бо через ріжні натяки, які — то в Різдвяних і Новорічних обрядах, то в радісних Колядкових окликах — говорять про слідуючий після Різдва й Богоявлення Великдень. А цей Великдень вважає тут нарід за Свято весняне, Свято обновленої природи і мабуть прилучується в тім до світових традицій і вірувань (Полудневого Сходу), що в цім великім дні буде колись Відродження Світа. Різдвяні взаємні віншування висловлюють побажання вимріяного непереривного щастя й добра: "від Різдва до Богоявління, від Богоявління до Воскресення", — іменно, здоровля, врожаїв у полі, щасливости в родині, многих літ. Те саме дослівно про містичний Святий час повторюють Колядки. Бог, Різдво Світа, Дідух і Лицарі. Різдво подумане у народу як уособлення культурної Сили, що принесла народові сільськогосподарські здобутки. Таким уособленням бувають у світовій мітології культурні лицарі. В Українців приявлює такого лицаря Прадід, добродій народу. Таким культурним лицарем, чи Спасителем (Heilbringer), є Св. Микола, а також Український Гаїлковий Див-Ладо (також: "Дід Ладо"), що наладив тай благословив сійбу проса, або Гаїлковий Галілей, що вчив чи помагав при Першій сійбі пшениці. А всі Святії за Погоничів за Посівачів. Поширення ідеї Дідуха та Корочуна в Українських Святах. Культурно-реліґійними традиціями про Прадіда пройнята є вся Староукраїнська реліґійна ідеологія і майже усі Українські народні свята. Постать Прадіда – Дідуха – Корочуна виступає сильно не лиш у святі Різдва-Коляди, але так само сильно й визначно у інших реліґійних і реліґійно-побутових Святах. ВИСЛОВЛЮВАННЯ: Біблія Українського народу. Піснї україньско-руского народа вяжуть ся тісно з єго житєм і подають вірне з''ображенє народного побуту від найдавнїйших часів, відколи нарід почав себе тямити, аж до нинїшного дня; у піснях зложив нарід свою сповідь, відкрив свою душу, виявив свободолюбні змаганя та зобразив вірно свою вдачу. Через народні піснї вчимо ся пізнавати людску душу, учимо ся розуміти і любити людий та цінити в кождім чоловіцї те, що в нїм є людского: наша народна поезия має образуючий і виховуючий вплив на широкі маси народу і ріжні єго верстви. Народні піснї — се неначе національна біблїя україньско-руского народу, се книга мудрости, у якій зложив нарід плоди свого довговікового досьвіду і тисячлїтної культури. Україньскі народні піснї визначають ся прекрасною формою пісенного складу і незвичайним богатством поетичного вислову. Християньске духовенство в інтересї церкви старало ся викоріняти серед народу давну віру, заказуючи і виклинаючи стародавні обрядові піснї, як "бісовскія пінія" або приноровлюючи сї піснї до християньских сьвятих і празників. Таким чином заведенє й розширенє християньскої віри спинило розвій давної релїґійної поезиї, а само християньство не змогло уже витворити у нас своєрідної національної поезиї релїґійної. — Степан Дубравський Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень: Українське Свято Відродження Світа. (Вибір Пісень) Про Українські назви місяців Марець і Май. Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Що означає "Дідух"? Стежки до листків про Українські традиції. Рокове Коло.','Вже Весна воскресла
