INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_11828','Журавлі','(Чуєш, брате мій...). Музика: Лев Лепкий Слова: Богдан Лепкий. Виконує: Василь Жданкін, Квітка Цісик, Анатолій Солов''яненко, Рената Бабак, Хор імені Григорія Верьовки, Державна заслужена академічна хорова капела Думка, Борис Гмиря, Капела бандуристів імені Тараса Шевченка, Володимир Вермінський, Іван Козловський','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,NULL,NULL,'Чуєш брате мій, товаришу мій,
