INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1186921','Слава нашим господарям','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Кисіль В.В., Чугуй О.П. Український новорічний обрядовий театр: Навчально-методичні матеріали для студентів філологічного факультету (спеціальність – українська мова та література). – Харків, 2009. – 21 с.',NULL,'Слава нашим господарям,
Що так ґречно нас приймали.
Щедрий вечір, добрий вечір,
Добрим людям на здоров''я!

Що так ґречно нас приймали,
Медом-пивом пригощали.
Щедрий вечір, добрий вечір,
Добрим людям на здоров''я!

Всі ми раді в цьому домі
Веселенько погуляти.
Щедрий вечір, добрий вечір,
Добрим людям на здоров''я!

Та на цей раз вибачайте —
Нам пора вже вирушати!
Щедрий вечір, добрий вечір,
Добрим людям на здоров''я!

Речитатив:
А за цими словами в дзвіночки дзвоним!
В дзвіночки дзвоним, а всім ся клоним!
Щастям, здоров''ям, ще й віком довгим!
Ще й віком довгим, прибутком добрим!
Від нині за рік та від року повік!
Христос народився! Славімо його!

Бувайте, бувайте, нас не забувайте,
Лихими словами та й не споминайте!
Але споминайте добрими словами,
Щоб були здорові многії літа ми!    Фонограма мінус (mp3)','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1186921'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1186921','Слава нашим господарям','Слава нашим господарям,
Що так ґречно нас приймали.
Щедрий вечір, добрий вечір,
Добрим людям на здоров''я!

Що так ґречно нас приймали,
Медом-пивом пригощали.
Щедрий вечір, добрий вечір,
Добрим людям на здоров''я!

Всі ми раді в цьому домі
Веселенько погуляти.
Щедрий вечір, добрий вечір,
Добрим людям на здоров''я!

Та на цей раз вибачайте —
Нам пора вже вирушати!
Щедрий вечір, добрий вечір,
Добрим людям на здоров''я!

Речитатив:
А за цими словами в дзвіночки дзвоним!
В дзвіночки дзвоним, а всім ся клоним!
Щастям, здоров''ям, ще й віком довгим!
Ще й віком довгим, прибутком добрим!
Від нині за рік та від року повік!
Христос народився! Славімо його!

Бувайте, бувайте, нас не забувайте,
Лихими словами та й не споминайте!
Але споминайте добрими словами,
Щоб були здорові многії літа ми!    Фонограма мінус (mp3)');
