INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1192606','Пречистая Діва церкву збудувала','Українська народна пісня. Виконує: Кумасеньки','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Пресвятая Діва церкву збудувала.
Радуйся!                       |
Радуйся небо, земля, веселися, |
Христос народився!             | (2)

І з трьома верхами, і з трьома вікнами.
Радуйся!                       |
Радуйся небо, земля, веселися, |
Христос народився!             | (2)

А в перше віконце світить ясне сонце.
Радуйся!                       |
Радуйся небо, земля, веселися, |
Христос народився!             | (2)

А в друге віконце світить ясен місяць.
Радуйся!                       |
Радуйся небо, земля, веселися, |
Христос народився!             | (2)

А в третє віконце світять ясні зорі.
Радуйся!                       |
Радуйся небо, земля, веселися, |
Христос народився!             | (2)

Янголи співають, Христа прославляють.
Радуйся!                       |
Радуйся небо, земля, веселися, |
Христос народився!             | (2)

А ми теж співаєм, Христа прославляєм.
Радуйся!                       |
Радуйся небо, земля, веселися, |
Христос народився!             | (2)','[''pisni.org.ua'', ''cat:christian'', ''cat:kolyadky'', ''cat:narodni'', ''Пісні на християнську тематику'', ''Колядки'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1192606'), datetime('now')),datetime('now'));
