INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1192024','Боже Великий',NULL,'uk','ukr_ssr_1919_1991',NULL,'1925',NULL,'"Спілка Української Молоді в Україні" є однією із найстарших молодіжних організацій і свій початок бере від підпільного СУМу, що існував у Києві в 1925-1929 роках. На сьогодні СУМ існує та діє в 10 країнах світу і є однією із двох найбільших виховних українських молодіжних організацій у світі. В сучасній Україні відродження СУМу розпочалося у 1989 році і з цього часу організація проводить виховну діяльність серед дітей та молоді. Методика сумівського виховання налічує понад 60 років й побудована на системі національного виховання, яку заклав відомий вітчизняний педагог Григорій Ващенко (почесний член СУМ, автор праці "Виховний ідеал"). За довголітню історію розвитку СУМу організацією було виховано багато відомих громадських діячів України та діаспори','Боже Великий, Творче всесвіту,
На нашу рідну землю споглянь
Ми були вірні Твому завіту,
Визволить рідний, батьківський край

Довго був край наш в рабстві, в руїні,
Тож просим в Тебе для нього ласк -
Боже Великий, дай Україні
Силу і славу, волю і власть.','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:himny-marshi'', ''Церковні пісні'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1192024'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1192024','Боже Великий','Боже Великий, Творче всесвіту,
На нашу рідну землю споглянь
Ми були вірні Твому завіту,
Визволить рідний, батьківський край

Довго був край наш в рабстві, в руїні,
Тож просим в Тебе для нього ласк -
Боже Великий, дай Україні
Силу і славу, волю і власть.');
