INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1193202','Коли звізда ясна','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Коли звізда ясна
З неба засвітила,
Тоді Діва Пречистая |
Сина породила       | (2)

Як го породила красно му співала:
"Чучай белай Синку Божий |
Бо я вже би спала"       | (2)

Не спи мамко не спи
За одну годину,
Заки я ти не принесу  |
Із рая перину         | (2)

Возьми Петре трубу
Затруби по всюду
Вже ся син божий народив |
Слава Пану Богу          | (2)','[''pisni.org.ua'', ''cat:christian'', ''cat:narodni'', ''Пісні на християнську тематику'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1193202'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1193202','Коли звізда ясна','Коли звізда ясна
З неба засвітила,
Тоді Діва Пречистая |
Сина породила       | (2)

Як го породила красно му співала:
"Чучай белай Синку Божий |
