INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1195000','А в кривого танця','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'RA-Media.uaprom.net',NULL,'А в Кривого Танця
Та не виведем Кінця!

Треба Єго та й виводити,
Лад Йому та й наводити.

Ой Вулиця та й Широкая,
Чого Трава невисокая?

Бо Парубки та й істоптали
Великими та й Ножищами,

Великими та й Ножищами,
Подертими Постолищами!

Ой Вулиця та Вузенькая,
Чого Трава Зелененькая?

Бо Дівоньки та й істоптали
Маленькими Ноженьками,

Маленькими Ноженьками,
Червоними та Чобітками.

Червоними та Чобітками,
