INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1195000','А в кривого танця','А в Кривого Танця
Та не виведем Кінця!

Треба Єго та й виводити,
Лад Йому та й наводити.

Ой Вулиця та й Широкая,
