INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1193529','Новий рік','Музика: Алла Івашина Слова: Я. Івашин. Виконує: Алла Івашина','uk','ukraine_1991',NULL,NULL,'http://allaivashyna.com.ua/',NULL,'Розтанула сніжинка на моїй долоні,
