INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1194707','Золотава осінь','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май, Гурт "Зоряна ніч", Петро Довгошия','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Осінній жовтий лист
Кружляє зверху вниз,
Свої наспівує пісні.
Ти кажеш - не журись,
Я повернусь колись -
Не обіцяй цього мені.
І марно не кажи,
І не тривож душі,
Мені лишилися пісні.
Бо знаю я сама,
Що йде до нас зима,
І так далеко до весни.

Приспів:
Золотава осінь
Розпустила коси
І птахом у небо летить.
За тобою буду
Все життя жаліти
І серденько буде боліть.
Золотава осінь
Йде простоволоса,
Шепоче мені - зупинись...
І питає вітра,
Де так довго він баривсь?..

І знову жовтий лист -
Від осені сюрприз -
Дарує усміх золотий,
Кажу слова не ті,
Гублюсь на самоті,
Лиш на прощання погляд твій.
І марно не кажи,
І не тривож душі,
Мені лишилися пісні,
Бо знаю я сама,
Що йде до нас зима
І так далеко до весни...

Приспів. (2)

Все питає вітра,
Де так довго він баривсь?','[''pisni.org.ua'', ''cat:lirychni'', ''cat:nostalgia'', ''Пісні про кохання, ліричні'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1194707'), datetime('now')),datetime('now'));
