INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1196529','Гаряча сльоза','Слова: Микола Джумак','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Перший крок по піску, перша втрата зв''язку
І черствіє душа за мить бою  одну!
Тільки серце людське береже суть свою
Й витискає від болю гарячу сльозу!

Приспів:
Афган у серці, Афган у душі!
Ти слід залишив у долі й житті!
І снитися завжди будуть мені -
Вибухи мін і крик в тишині!

Ту гарячу сльозу понесуть журавлі
По вкраїнській землі, по афганській землі!
І крізь неї побачать народи усі
Рани друзів моїх і війні скажуть: "Ні!"

Ту гарячу сльозу і в дім свій принесу!
Батька й матір своїх до грудей пригорну!
І про друзів своїх я усе розкажу,
Вічну пам''ять про них у душі збережу.','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1196529'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1196529','Гаряча сльоза','Перший крок по піску, перша втрата зв''язку
І черствіє душа за мить бою  одну!
Тільки серце людське береже суть свою
Й витискає від болю гарячу сльозу!

Приспів:
Афган у серці, Афган у душі!
Ти слід залишив у долі й житті!
І снитися завжди будуть мені -
Вибухи мін і крик в тишині!

Ту гарячу сльозу понесуть журавлі
По вкраїнській землі, по афганській землі!
І крізь неї побачать народи усі
Рани друзів моїх і війні скажуть: "Ні!"

Ту гарячу сльозу і в дім свій принесу!
