INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1196220','Сонце сідає, ніч наступає','Музика: Сергій Татієнко Слова: Валентина Юрченко. Виконує: Тріо Либідь','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Сонце сідає,
Ніч наступає,
Спів соловейка
Чути у гаї.
Дрімають вікна
Хатин чепурненьких,
Десь чути пісню
Дитині маленькій...

Приспів:
Спи, моє любе,
Сил набирайся...
Спи і до ранку
Не просинайся...
Сон твій спокійний
Я охороняю,
Бо щастя більшого
За тебе не маю...
Люлі-люлі, люлі-люлі..

Я вже й не знаю
Снів тих чарівних,
Роки, як свічка,
Швидко згоріли...
В щасті ніколи
Мені вже не жити,
З щастя твого
Можу тільки радіти...

Приспів.

Ніч опустилась,
Чути у гаю,
Як соловейко
Пісню співає...
Наче в долонях,
Стискає серденько
Та колискова
Дитині маленькій...

Приспів.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1196220'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1196220','Сонце сідає, ніч наступає','Сонце сідає,
Ніч наступає,
