INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1198622','День подяки',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'У нас сьогодні День Подяки
Творцеві за дари усякі:
Em
За хліб, повітря і за воду
Для нас і нашого народу.

Hm
За сонце, що так гарно гріло,
A
Що в нас ніщо не погоріло,
За дощ, що зрошував насіння,
За всі Його благословіння.

Що кожний день нам сходить сонце,
Пташки співають нам в віконце.
За ліс і луки, всі простори,
Що в темну ніч нам сяють зорі.

Коли закінчим сіять, жати,
Покличуть нас відпочивати.
Земна закінчиться дорога,
Там будем вічно славить Бога.','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1198622'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1198622','День подяки','У нас сьогодні День Подяки
Творцеві за дари усякі:
Em
За хліб, повітря і за воду
Для нас і нашого народу.

Hm
За сонце, що так гарно гріло,
A
Що в нас ніщо не погоріло,
За дощ, що зрошував насіння,
За всі Його благословіння.

Що кожний день нам сходить сонце,
Пташки співають нам в віконце.
За ліс і луки, всі простори,
Що в темну ніч нам сяють зорі.

Коли закінчим сіять, жати,
Покличуть нас відпочивати.
Земна закінчиться дорога,
Там будем вічно славить Бога.');
