INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1206127','Новорічні сни','Музика: Марія Бурмака Слова: Марія Бурмака. Виконує: Марія Бурмака','uk','ukraine_1991',NULL,NULL,'http://blog.meta.ua/~maria_burmaka/posts/i886918/',NULL,'Казка починається з початку,
Новий Рік ступає на поріг.
Мрії, сподівання - як закладки
Згадуються тільки в Новий Рік.
Срібне павутиння заметілі
Засипає все минуле в тінь,
Значить буде все, як ти хотіла,
Буде все, як ти того хотів!

Приспів:
Новорічні сни -
Ще далеко до весни,
Хай любов тобі насниться,
Ніжна, як дитячій сміх!
Новорічні сни -
Непомітно для усіх
Щастя хай тебе розбудить
Тихо, як ранковий сніг!

Хай мороз на вікнах намалює
Знаки невідомої зими
І надію знову подарує -
Всі ми залишилися дітьми.
Новорічна свічка догорає,
Ніч зимову засипає сніг,
Ти не знаєш, хто тебе чекає,
Хто іще зустрінеться тобі.

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1206127'), datetime('now')),datetime('now'));
