INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1207323','Плач, кохана, плач','Українська народна пісня. Виконує: Львівські музики','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Забулися гарячі поцілунки,
Минулися чудові вечори,
Як часто ми з тобою зустрічались,
Тепер ми розійшлися назавжди...

Приспів:
Плач, кохана, плач,    |
Тебе я розлюбив,       |
А, може, я тебе ніколи |
Не любив...            | (2)

Ти плачеш, ти ридаєш, ти смієшся,
Ти хочеш повернути ту любов,
Але любов ніколи не вернеться,
Не вернеться вона ніколи знов...

Приспів.

У сні до мене ти приходиш часто,
Ти хочеш повернути ту любов,
Ти плачеш, ти ридаєш, ти смієшся,
Немов з тобою ми зустрілись знов...

Приспів. (2)','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1207323'), datetime('now')),datetime('now'));
