INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1205505','Парасольки','Музика: Василь Лисенко Слова: Галина Лисенко','uk','ukraine_1991',NULL,NULL,'http://icesun.com.ua',NULL,'Кап-кап-кап - дощик пройшов,
Кришталевий дзвоник знайшов.
І так гарно ним награвав,
І до танцю нас закликав!

Приспів:
Парасольки, парасольки
Тримаємо ми,
Кольорові парасольки
Чарівні такі!
Парасольки, парасольки -
Краплинки летять,
Кольорові парасольки
Нас захистять!

Кап-кап-кап - дощик з небес -
Для малят стільки чудес!
І так гарно він награвав,
І до танцю нас закликав!

Приспів. (2)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1205505'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1205505','Парасольки','Кап-кап-кап - дощик пройшов,
Кришталевий дзвоник знайшов.
І так гарно ним награвав,
І до танцю нас закликав!

Приспів:
Парасольки, парасольки
Тримаємо ми,
Кольорові парасольки
Чарівні такі!
Парасольки, парасольки -
Краплинки летять,
Кольорові парасольки
Нас захистять!

Кап-кап-кап - дощик з небес -
Для малят стільки чудес!
І так гарно він награвав,
І до танцю нас закликав!

Приспів. (2)');
