INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1201921','Чудову пісню',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Чудову пісню Спас мені дав
З небесної висоти.
Такої я ще ніколи не співав,
То мелодія любві.

В моїм серці є мелодія,
Така чудова є,
В моїм серці є мелодія
Про Спасителя Христа.

Любов Христа, що вмер Він за нас,
Дала мені вже життя
І в серці вселила мелодію,
Радію тепер вже я.

Буду співати Спасові я,
Коли зійдемося всі.
О, як буде там мені радісно,
Коли зустріну своїх.','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1201921'), datetime('now')),datetime('now'));
