INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1206101','Лілія','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Не сама, не сама
Лілію садила,
Не сама, не сама
Лілію ростила!

Приспів:
Ой, ти ж, моя лілія,
Рости ж, моя лілія,
Рости ж, моя лілія,
Ти - моя лілея!

Ми удвох, ми удвох
Лілію садили,
Ми удвох, ми удвох
Лілію ростили!

Приспів.

Нащо брав, нащо брав
Мене невеличку?
Цілував, обнімав,
Як перепеличку?..

Приспів.

Ой, чому ж ти не прийдеш?
Мене заміж не візьмеш?
Мене заміж не візьмеш,
Ти - моя лілея?','[''pisni.org.ua'', ''cat:lirychni'', ''cat:narodni'', ''Пісні про кохання, ліричні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1206101'), datetime('now')),datetime('now'));
