INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1203707','Ой, кувала зозуленька','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, кувала зозуленька
У вечорі в садочку,
Танцювала подруженька
У моїм віночку.

Приспів:
Віночок весільний з себе знімаю,
Подружку любую я обнімаю.
Віночок весільний більш не одіну,
Ранки дівочії я не зустріну.

Розплітали подруженьки
Мої русі коси,
А ті коси та й збирали
Сліз дівочих роси.

Приспів.

Ой, подружки, подруженьки,
Ми разом зростали,
Разом з вами веселенько
Молодість гуляли.

Приспів.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1203707'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1203707','Ой, кувала зозуленька','Ой, кувала зозуленька
