INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_121000','Ой сів Христос вечеряти','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой сів Христос вечеряти,
Щедрий вечір,
Добрий вечір,
Добрим людям на здоров''я!

Пришла до Нього Божа Мати,
Щедрий вечір,
Добрий вечір,
Добрим людям на здоров''я!

Ой, дай, Сину, райські ключі -
Щедрий вечір,
Добрий вечір,
Добрим людям на здоров''я!

Одімкнути рай і пекло,
Щедрий вечір,
Добрий вечір,
Добрим людям на здоров''я!

Випустити грішні душі.
Щедрий вечір,
Добрий вечір,
Добрим людям на здоров''я!

Одні си не пускати:
Щедрий вечір,
Добрий вечір,
Добрим людям на здоров''я!

Що налаяла отца й матір,
Щедрий вечір,
Добрий вечір,
Добрим людям на здоров''я!

Не налаяла, а подумала.
Щедрий вечір,
Добрий вечір,
Добрим людям на здоров''я!','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''Колядки'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_121000'), datetime('now')),datetime('now'));
