INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1219323','За Миколу!','Музика: Микола Янченко Слова: Микола Янченко. Виконує: Микола Янченко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Тягне воза кобила,
Тягне Галю до Данила,
А мене тягне в рідне село!
Тут душа моя радіє,    |
Тут душа моя весніє,   |
Тут родинне моє тепло! | (2)

Приспів:
За Миколу, за Миколу
Пустим чарочку по колу!
Хай ростуть в його ставочку
Карасі!
За Миколу, за Миколу,  |
Щоб, як діти у школу,  |
Йшли до нього в хату   |
Гості усі!             | (2)

Не та пісня без Миколи,
Не гудуть на липі бджоли,
Якщо липу ту Микола не садив.
І ніколи, козаче,      |
За тобою не заплаче    |
Вірний кінь,           |
Якщо ти його бив!      | (2)

Приспів. (3)','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1219323'), datetime('now')),datetime('now'));
