INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1208202','Біля річки, біля броду','Українська народна пісня. Виконує: Гурт "Зоряна ніч"','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Біля річки, біля броду
Дівчина стоїть,
Задивилася на воду
Й тихо говорить:

Приспів:
Ой, чом, чом я,
Чом я не красива?..
Ой, чому, чому
Не красива, нещаслива,
Бо тебе люблю...

Місяць світить, зорі сяють,
Я сиджу в саду,
Ти не прийдеш, не спитаєш,
Кого я люблю...

Приспів.

Мій коханий, серце моє,
Ти - любов моя,
Я чекаю, виглядаю,
А тебе нема...

Приспів.

Мила моя синьоока,
Сонця ясен світ,
Я душею за тобою
Лину у весь світ!

Приспів','[''pisni.org.ua'', ''cat:narodni'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1208202'), datetime('now')),datetime('now'));
