INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1227404','На Почаєвській горі','Українська народна пісня. Виконує: Ансамбль Многая лєта','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'На Почаєвській горі
Божа мати стояла.
Боже, Боже,
Божа мати стояла.
Боже, Боже,
Божа мати стояла.

Почаєвський монастир -
Там зібрався й увесь мир.
Боже, Боже,
Там зібрався й увесь мир.
Боже, Боже,
Там зібрався й увесь мир.

Божа мати стояла,
Свого сина вмовляла.
Боже, Боже,
Свого сина вмовляла.
Боже, Боже,
