INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1214529','Погони','Музика: Браття Слова: Браття. Виконує: Браття','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми вибрали долю,
Чи доля призначила нас
Служити народу день-в-день
Від присяги в запас,
Узявши собі в настанову
Батьківські слова:
Це честь і порядність,
Це сила і правда свята!
І віру нам дали, надію,
А також любов,
Щоб мир берегли,
Щоб не проливалася кров,
А треба на захист -
Пліч-о-пліч стаєм, як один,
Не бути неправді
І злу біля нас не пройти!

Приспів:
Погони на плечі лягли,
Щоб люди не знали біди.
Погони - це значить для нас
Держава, закон, честь, наказ!

Ми знаєм, так було
У різні часи і віки,
Що люди в погонах
Наш спокій завжди берегли,
І вас пам''ятаєм,
Загиблі батьки і діди,
Ми також в погонах,
Дивіться, ми - справжні орли!

Приспів. (2)

Погони - це значить для нас
Держава, закон, честь, наказ!','[''pisni.org.ua'', ''cat:viyskovi'', ''Пісні на військову тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1214529'), datetime('now')),datetime('now'));
