INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1212725','Обручка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'У весільный заметілі
Закрутило разом нас,
А на дворі була осінь -
Справді був чудовий час!
Листя падало до долу,
Мов стилилося до ніг,
І святковий вечір цей
Я в душі зберіг!

Приспів:
А обручка на правій руці
Знов нагадує вечір,
Як лунали вітання для нас,
Ти щаслива була,
Як твоя білосніжна фата
Розляглася на плечі
І рікою лилася любов,
Що двоїх нас з тобою звела!

Я пригадую троянди білі,
Білі на весні,
І тебе в весільній сукні
І гостей веселий сміх,
Як ми танцювали вальс,
Який для молодих звучав,
І цей день на все життя
Я запам''ятав!

Приспів.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1212725'), datetime('now')),datetime('now'));
