INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1225909','Ворожила','Музика: Маріанна Ільків Слова: Маріанна Ільків. Виконує: Маріанна Ільків','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'В ніч на Івана,
В ніч на Купала
Свічу я запалила,
На тебе ворожила.
Золотом з колосся
Я плела волосся,
Тебе причарувала,
В ту ніч на Купала!

Приспів:
Ворожила доля,
Що любов - неволя
Їй не вірили ми...
Ворожили люди,
Що життя нам не буде -
Помилялись вони.

Не забуду тої ночі,
Як здійснився сон дівочий,
Нас небо обіймало,
Коханням чарувало...
Ті твої зелені очі
Снилися мені щоночі,
Я землю обійшла
Та все одно тебе знайшла!

Приспів. (2)','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1225909'), datetime('now')),datetime('now'));
