INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1238808','Весна','Музика: Вадим Красноокий Слова: Вадим Красноокий. Виконує: Mad Heads (XL)','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Знову цвітуть каштани,
Хвиля Дніпровська б''є,
Посеред міста стану,
Гупає серце моє.
Радощі душу на поїзд погнав,
Знову у Києві весна
Вулицями гуляє, вулицями гуляє!
Пахощі вітер несе п''янкі,
Мов коло мене дівчата стрункі,
Хтось же їх всіх кохає,
Хтось же їх всіх кохає!

Хтось же їх всіх кохає! | (3)
Хтось же всіх їх!..

А весна розпускає чари,
Співає на всі голоси,
Та більшої, ніж дівчата,
В природі нема краси.
Веселі, задумливі і сумні,
Вони всі подобаюся мені,
Що я робити маю?..
Що я робити маю?..
Високі, низенькі, пухкі, худі,
Білявки, чорненькі і руді
І хтось же всіх їх кохає!
Хтось же їх всіх кохає!

Хтось же їх всіх кохає! | (3)
Хтось же всіх їх!..

О, поки у Києві весна,
Може, там десь є така одна,
Єдина для мене та є,
Єдина для мене та є.
Знайду - і на все життя лиш вона,
Та знову у Києві весна,
І хтось же їх всіх кохає,
Хтось же їх всіх кохає!

Хтось же їх всіх кохає! | (3)
Хтось же всіх їх!..','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1238808'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1238808','Весна','Знову цвітуть каштани,
