INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1233101','Купальський вінок','Музика: Ірина Доля Слова: Ірина Доля. Виконує: Ірина Доля, тріо','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Бачу у небі свою зорю,
Світить вона чи ні,
Зіронько мила, любов мою
Ти принеси мені!

Приспів:
Я вінок в Купальську ніч |
По воді пускала,         |
А до тебе мати знов      |
Мене не пускала.         | (2)

Плину по небу у ніч ясну
В місячному човні,
Зорі колишуть усе до сну,
Любий, наснись мені!

Приспів.','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1233101'), datetime('now')),datetime('now'));
