INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1230404','Дас іст гуд фантастіш','Музика: Михайло Хома, Олег Турко Слова: Михайло Хома, Олег Турко. Виконує: DZIDZIO','uk','ukraine_before_1917',NULL,NULL,'відеозапис',NULL,'Тобі вже вісімнадцять
І ти на всьо готова,
А ми не говорили
Про секс ще ані слова.
Я вже не можу більше
Ту тєму відкладати,
Мені вже надоїло
І я махав чекати.

Приспів
Das іst good fantastіsch, |
Das іst good, ya, ya!     |
Чуєш, хочу я!             | (2)

Я про любов глибоку
Німецький фільм дивився,
Реально еротичний
Про тебе сон приснився.
Мені ти шепотіла:
Ich lіebe dіch ja wohl...
А я відповідав
Любовних слів пароль.

Приспів.

Якась твоя подруга
До мене подзвонила,
Мене чомусь без тебе
До себе запросила.
Ти маєш зрозуміти:
Я мушу взрослим стати,
Мені вже надоїло
І я махав чекати.

Приспів.','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1230404'), datetime('now')),datetime('now'));
