INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1240921','Ой, пусти вінок','Музика: Сергій Сольоний Слова: Олесь Бердник. Виконує: Віктор Пашник','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой пусти вінок в потік потічок
Понесе його весняна вода.
Ти за ним іди, ти у слід гляди -    |
Де твоя любов, де твоя судьба.      |

Як вінок пристав там, де тихий став -
Буде муж тебе тішити в житті,
Буде цілувать, буде милувать,       |
Ружі заплітать в кісники густі.     | (2)

Як у водокрут хвилі понесуть
Твойого вінка - ти за ним біжи.
Наречений твій десь тримає бій -    |
Ти йому своїм серцем поможи.        | (2)

Як вінок пірне - доленька мине
Стороною твій одинокий дім.
Тільки не журись, все одно колись   |
Заспіває птах в серденьку твоїм.    | (2)','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1240921'), datetime('now')),datetime('now'));
