INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1234000','Ірод Цар за Христом ганявся','Музика: різні версії Слова: народні','uk','ukraine_before_1917',NULL,NULL,'http://nashe.com.ua/song.htm?id=11014','http://nashe.com.ua/images/notes/11014-14.gif','Ірод цар за Христом ганявся,
Він за ним дуже побивався,
На сідельці не вдержався,
З кобильчини обірвався
Та й упав на шлях.

Він лежить, ледве дух одводить,
Кобильчина кругом його ходить,
Йому в вічі заглядає,
Хвостом мухи обганяє
Та й порска на вид.

Іродиха як теє зачула,
Що ввірвалась у царя мотуга,
Зірвалася з ліжка боса,
Та як є простоволоса
Йому навздогін.

Іродята дуже ізлякались
Та за нею всі бігцем подались.
Коновками воду носять,
Ревуть, плачуть ще й голосять:
"Пропав Ірод наш!"','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1234000'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1234000','Ірод Цар за Христом ганявся','Ірод цар за Христом ганявся,
