INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1241220','Про жабенятко','Музика: Олег Рубанський Слова: Олег Рубанський. Виконує: Олег Рубанський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Може є у когось кіт,
А в когось цуценя,
А у нас поза тим літом
Жило жабеня.
Ми йому казки читали,
Морозивом пригощали,
І кумедну пісню склали,
І йому співали.

Приспів:
Ква-ква-ква-ква-ква-ква!
Ква-ква-ква-ква-ква-ква!
Ква-ква-ква-ква-ква-ква!
Ква-ква-ква-ква-ква-ква!

Ой, були нам до вподоби
Враження нові!
З жабенятком ми у жмурки
Гралися в траві.
Ми раділи з жабенятком,
Ми стрибали з жабенятком,
І стрибали з жабенятком -
Уявіть собі!

Приспів.

Швидко літо промайнуло
І одного дня раптом зникло,
Як не було, наше жабеня
Ми три дні його шукали,
Потім осінь всю чекали,
Потім зиму сумували
Ми без жабеня...

Якось раз наступним літом
Ми прийшли в садок,
І побачили там повний
Жабенят ставок!
Ой, чи знаєте, малятка,
Де шукати жабенятка,
Де? І раптом відізвавсь
Хором весь ставок:
"Ква-ква-ква-ква-ква-ква!"
Ми впізнали нашу пісню,
От такі дива! І у той момент,
В той чудний момент
Жабенятко наше,
Гляньте, вирина!..

Приспів. (2)','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1241220'), datetime('now')),datetime('now'));
