INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1237000','Не думай про завтра','Музика: Андрій Кузьменко Слова: Андрій Кузьменко. Виконує: Скрябін','uk','ukraine_1991',NULL,NULL,'аудозапис',NULL,'Ти знаєш, не переживай,
Все буде добре!..
І, навіть, в іншому житті
Ми будем двоє!
Одінь для мене, як в той раз,
Своє краще плаття,
І будем на білому піску
З тобою лежати.

Приспів:
Не думай про завтра,
Це за тисячу років,
А я завжди поряд!
І що таке щастя -
Не знають мільйони,
А ми його творим!
Давай ще сьогодні
Покажемо людям,
Як треба любити!
Не думай про завтра,
Ще так багато треба зробити.

Сідай зі мною на диван
Моєї машини,
Давай, подивимось на світ,
Як ніби з вітрини.
У нас тут свій маленький рай
Незрозумілий,
Захлопни двері, не питай
Коли ми приїдем...

Приспів.

Не думай про завтра,
Це за тисячу років...
І що таке щастя -
Не знають мільйони...
Давай ще сьогодні
Покажемо людям,
Як треба любити!
Не думай про завтра,
Ще так багато нам
Треба зробити.','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1237000'), datetime('now')),datetime('now'));
