INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1251127','Пора, мати, жито жати','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські народні пісні з нотами. Кого люблю — Мій буде / Упоряд. Г. І. Ганзбурґ; Худож.-оформлювач Л. Д. Киркач. — Харків: Фоліо, 2004. — 287 с.',NULL,'Пора, мати, жито жати:
Колос похилився,
Пора дочку заміж дати:
Голос одмінився.

Хоч колосок похилився,
Стебло зелененьке,
Хоч голосок одмінився,
Личко молоденьке.

Посилає мене мати
У степ жито жати,
Аж там чумак воли пасе, —
Став зо мною жартувати.

Жартуй, жартуй, чумаченьку,
Жартуй, коли любиш,
як підеш у дорогу,
То мене забудеш!

Не забуду, моя мила,
Буду поспішати,
А як прийду додомоньку,
Сватів буду слати!

Весна-красна наступає,
Із стріх вода капле,
Молодому чумакові
Шлях-дорога пахне.

У, неділю ранесенько,
Саме на схід сонця,
Заплакала дівчинонька,
Глядячи в віконце:

Чому мене, моя нене,
Рано не збудила,
А як тая чумачина
З села виїздила?

Тим я тебе, моя доню,
Рано не збудила, —
Попереду твій миленький, —
Щоб ти не тужила!

Ти думаєш, моя нене,
Що я й так не плачу?
За дрібними слізоньками
Вже й світу не бачу!

Ой, я б була, моя нене,
Зовсім не тужила,
Коли б тільки миленькому
Доленька служила!

Ти думаєш, моя нене,
Що й так не журюся?
Ой, як вийду за ворота, —
Од вітру валюся!','[''pisni.org.ua'', ''cat:chumacki'', ''Чумацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1251127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1251127','Пора, мати, жито жати','Пора, мати, жито жати:
Колос похилився,
Пора дочку заміж дати:
Голос одмінився.

Хоч колосок похилився,
Стебло зелененьке,
Хоч голосок одмінився,
Личко молоденьке.

Посилає мене мати
У степ жито жати,
Аж там чумак воли пасе, —
Став зо мною жартувати.

Жартуй, жартуй, чумаченьку,
Жартуй, коли любиш,
як підеш у дорогу,
То мене забудеш!

Не забуду, моя мила,
Буду поспішати,
А як прийду додомоньку,
Сватів буду слати!

Весна-красна наступає,
Із стріх вода капле,
Молодому чумакові
Шлях-дорога пахне.

У, неділю ранесенько,
Саме на схід сонця,
Заплакала дівчинонька,
Глядячи в віконце:

Чому мене, моя нене,
Рано не збудила,
А як тая чумачина
З села виїздила?

Тим я тебе, моя доню,
Рано не збудила, —
Попереду твій миленький, —
Щоб ти не тужила!

Ти думаєш, моя нене,
Що я й так не плачу?
За дрібними слізоньками
Вже й світу не бачу!

Ой, я б була, моя нене,
Зовсім не тужила,
Коли б тільки миленькому
Доленька служила!

Ти думаєш, моя нене,
Що й так не журюся?
Ой, як вийду за ворота, —
Од вітру валюся!');
